            var result = EmailPattern.Replace(input, "[EMAIL_REDACTED]");
            result = SsnPattern.Replace(result, "[SSN_REDACTED]");
            result = CreditCardPattern.Replace(result, "[CC_REDACTED]");
            result = PhonePattern.Replace(result, "[PHONE_REDACTED]");
            return result;
        }

        public static string RedactSqlParameters(SqlCommand command)
        {
            var sb = new StringBuilder();
            sb.AppendLine($"Query: {command.CommandText}");
            sb.Append("Parameters: ");

            var paramList = new List<string>();
            foreach (SqlParameter param in command.Parameters)
            {
                var paramName = param.ParameterName.ToLowerInvariant();
                bool isSensitive = SensitiveBodyFields.Any(f =>
                    paramName.Contains(f, StringComparison.OrdinalIgnoreCase));

                var displayValue = isSensitive
                    ? "[REDACTED]"
                    : RedactPiiPatterns(param.Value?.ToString() ?? "NULL");

                paramList.Add($"{param.ParameterName}={displayValue}");
            }

            sb.Append(string.Join(", ", paramList));
            return sb.ToString();
        }

        /// <summary>
        /// Creates a correlation-safe user identifier (hashed) for log tracing
